import express from 'express';
import path from 'path';
import fs from 'fs';
import { createServer as createViteServer } from 'vite';

const app = express();
const PORT = 3000;

// Set up JSON body parser with 10mb limit for base64 logo uploading
app.use(express.json({ limit: '10mb' }));

// Set up public/assets static directories
app.use('/assets', express.static(path.join(process.cwd(), 'src/assets')));

// Ensure folders exist
const logoDir = path.join(process.cwd(), 'logo');
const logo2Dir = path.join(process.cwd(), 'logo2');
if (!fs.existsSync(logoDir)) {
  fs.mkdirSync(logoDir, { recursive: true });
}
if (!fs.existsSync(logo2Dir)) {
  fs.mkdirSync(logo2Dir, { recursive: true });
}

// Serve logo files statically
app.use('/logo', express.static(logoDir));
app.use('/logo2', express.static(logo2Dir));

// Dynamic Logo endpoint
// Returns logo2/logo.png if it exists, otherwise logo/logo.png
app.get('/api/logo.png', (req, res) => {
  const customLogoPath = path.join(logo2Dir, 'logo.png');
  const defaultLogoPath = path.join(logoDir, 'logo.png');
  
  if (fs.existsSync(customLogoPath)) {
    return res.sendFile(customLogoPath);
  } else if (fs.existsSync(defaultLogoPath)) {
    return res.sendFile(defaultLogoPath);
  } else {
    // Ultimate fallback if default doesn't exist
    return res.status(404).send('Logo not found');
  }
});

// Endpoint to upload a custom logo (saved into logo2/logo.png)
app.post('/api/upload-logo', (req, res) => {
  const { logoData } = req.body;
  if (!logoData) {
    return res.status(400).json({ error: 'No logo data provided' });
  }

  try {
    // Strip metadata prefix if base64
    const base64Data = logoData.replace(/^data:image\/\w+;base64,/, "");
    const buffer = Buffer.from(base64Data, 'base64');
    
    const customLogoPath = path.join(logo2Dir, 'logo.png');
    fs.writeFileSync(customLogoPath, buffer);
    
    return res.json({ success: true, logoUrl: '/api/logo.png' });
  } catch (error: any) {
    console.error('Error writing custom logo:', error);
    return res.status(500).json({ error: 'Failed to write logo to file system' });
  }
});

// Endpoint to delete custom logo from logo2 folder
app.post('/api/delete-logo', (req, res) => {
  try {
    const customLogoPath = path.join(logo2Dir, 'logo.png');
    if (fs.existsSync(customLogoPath)) {
      fs.unlinkSync(customLogoPath);
      return res.json({ success: true });
    } else {
      return res.json({ success: true, message: 'Custom logo was already empty' });
    }
  } catch (error: any) {
    console.error('Error deleting custom logo:', error);
    return res.status(500).json({ error: 'Failed to delete logo from file system' });
  }
});

