// Endpoint to send or simulate a test notification push using OneSignal
app.post('/api/send-test-push', async (req, res) => {
  const { title, message, targetType, targetValue, recipientName, senderName } = req.body;
  
  const onesignalAppId = process.env.ONESIGNAL_APP_ID;
  const onesignalApiKey = process.env.ONESIGNAL_API_KEY;
  
  const hasPushConfig = !!(onesignalAppId && onesignalApiKey);
  
  console.log(`[OneSignal Push Test] Tentando enviar push. Título: ${title}. Destino: ${targetType} (${targetValue})`);
  
  const pushTitle = title || 'Alerta do Tatame 🥋';
  const pushMessage = message || 'Este é um teste de notificação push em tempo real.';
  
  if (hasPushConfig) {
    try {
      const body: any = {
        app_id: onesignalAppId,
        headings: { en: pushTitle, pt: pushTitle },
        contents: { en: pushMessage, pt: pushMessage },
      };
      
      if (targetType === 'all') {
        body.included_segments = ['Subscribed Users'];
      } else if (targetType === 'player_id') {
        body.include_subscription_ids = [targetValue];
      } else if (targetType === 'user_id') {
        // External user ID integration
        body.include_aliases = {
          external_id: [targetValue]
        };
        body.target_channel = 'push';
      } else {
        body.included_segments = ['Subscribed Users'];
      }
      
      const response = await fetch('https://onesignal.com/api/v1/notifications', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json; charset=utf-8',
          'Authorization': `Basic ${onesignalApiKey}`
        },
        body: JSON.stringify(body)
      });
      
      const data = await response.json();
      if (response.ok) {
        console.log(`[OneSignal Push Test] Notificação enviada com sucesso!`, data);
        return res.json({
          success: true,
          realDelivery: true,
          provider: 'OneSignal',
          details: data
        });
      } else {
        console.error(`[OneSignal Push Test] Erro retornado pela API do OneSignal:`, data);
        return res.status(400).json({
          success: false,
          error: data.errors ? (Array.isArray(data.errors) ? data.errors.join(', ') : JSON.stringify(data.errors)) : 'Erro desconhecido na API do OneSignal.',
          details: data
        });
      }
    } catch (err: any) {
      console.error('[OneSignal Push Test] Erro ao disparar push via OneSignal:', err);
      return res.status(500).json({
        success: false,
        error: `Erro ao enviar push via OneSignal: ${err.message}`
      });
    }
  } else {
    console.log(`[OneSignal Push Test] OneSignal não configurado. Retornando simulação de alta fidelidade.`);
    return res.json({
      success: true,
      realDelivery: false,
      onesignalConfigured: false,
      message: 'Servidor OneSignal não configurado. Para disparar notificações reais, adicione as credenciais no menu Settings.',
      details: {
        appId: onesignalAppId || 'MOCK_ONESIGNAL_APP_ID_12345',
        title: pushTitle,
        message: pushMessage,
        targetType: targetType || 'all',
        targetValue: targetValue || 'Subscribed Users',
        instructions: 'Para habilitar o envio de push reais, configure as variáveis de ambiente ONESIGNAL_APP_ID e ONESIGNAL_API_KEY no menu Settings do Google AI Studio.'
      }
    });
  }
});

// Dev vs Production Setup
async function setupServer() {
  if (process.env.NODE_ENV !== 'production') {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, '0.0.0.0', () => {
    console.log(`[TeamGorilas] Full-stack Server listening on http://localhost:${PORT}`);
  });
}

setupServer();
